# util compartido evita import circular a↔b
def util_norm(s: str) -> str:
    return s.strip().casefold()

def a_side(s):
    return util_norm(s)

def b_side(s):
    return util_norm(s) + '!' 
print('ok', a_side(' Hi '), b_side(' Hi '))

