def normalize(s: str) -> str:
    return s.strip().casefold()

def compare(a: str, b: str) -> bool:
    return normalize(a) == normalize(b)

__all__ = ['normalize', 'compare']
print(__all__)
print(compare(' Ana ', 'ana'))

